            aWandererD = aWandererD ^ (((RotL64(aScatter, 23U) + aOrbiterH) + RotL64(aOrbiterC, 60U)) + aPhaseDWandererUpdateSaltB[(((31U - aIndex) + 18U)) & S_SALT1]);
