            aOrbiterK = RotL64((aOrbiterK * 0xEB77046CBB87344FULL), 57U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterG) + 0x8CCA95DEAB040982ULL) + aPhaseCOrbiterUpdateSaltE[(((31U - aIndex) + 9U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterA) ^ 0x603F7B9E1F5F571AULL;
            aOrbiterC = RotL64((aOrbiterC * 0x106F62C897D2BC07ULL), 41U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterH) + 0x7B0CCD3F03A83CDAULL;
            aOrbiterE = ((aOrbiterE ^ aOrbiterC) ^ 0x2796D5E612883053ULL) ^ aPhaseCOrbiterUpdateSaltA[((aIndex + 19U)) & S_SALT1];
            aOrbiterE = RotL64((aOrbiterE * 0xC45EDB0A1B7770EDULL), 5U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterK) + 0x965654EE79D72420ULL;
